sql:
SELECT class_id, COUNT(*) as total_shareholders
FROM shareholders
GROUP BY class_id;

SELECT COUNT(*) 
FROM share_transactions 
WHERE class_id = 0;

external_knowledge:
- 'significant purchases' refers to transactions where the total number of shares purchased exceeds 500;
- 'class names and identifiers' refer to the class_name and class_id in the database;
- 'total transactions' and 'total shares' refer to the count of transactions and sum of shares involved in the purchases, respectively;
- 'average price per share' is the average cost of each share across the transactions.

sql:
SELECT transaction_type, total_amount 
FROM share_transactions 
WHERE total_amount > 1000;

SELECT COUNT(transaction_id) AS Total_transactions
FROM share_transactions
WHERE class_id = 0 AND strftime('%Y', transaction_date) = '2022';

SELECT purchase_date
FROM shareholders
WHERE shareholder_id = 1;

SELECT MAX(transaction_date) AS most_recent_transaction
FROM share_transactions
WHERE shareholder_id = (SELECT shareholder_id FROM shareholders WHERE shareholder_name = 'John Doe');

SELECT COUNT(*) AS total_purchases
FROM share_transactions
WHERE shareholder_id = (
  SELECT shareholder_id 
  FROM shareholders 
  WHERE total_invested = (
    SELECT MAX(total_invested) 
    FROM shareholders
  )
) AND transaction_type = 'purchase';

SELECT period_id, from_year, to_year, period_description, is_open, created_at, updated_at, ROWID AS unique_id
FROM financial_periods
WHERE period_id > 0;
